module.exports = function(RED) {

    function trgAtLeastNode(config) {
        RED.nodes.createNode(this, config);

        var node = this;
        var on_time = parseInt(config.on_time||864000,10);
        var on_duration = parseInt(config.on_duration||300,10);
        var on_payload = config.on_payload;
        var off_payload = config.off_payload;
        var timer1 = setTimeout(function() {
                setOnTimer();
                node.status({text:"Timed:"+on_time});
            },500);
        var timer2 = setTimeout(function() {},5)
        var reset = false;
        var lastOnMsg = { topic : "empty", payload: "ON" };
        // Start timers

        this.on('input', function(msg) {
			var signal = msg.payload;
			if (signal.toUpperCase() == on_payload.toUpperCase()) {
				// Reset Timers, Mark On received.
                // stop timers
                offTimers();
                node.status({fill:"green",shape:"dot",text:on_payload+" received,send"});
                lastOnMsg = { topic : msg.topic, payload: msg.payload };
                if (!reset) {
                    node.send(msg);
                }
                reset = true;
			} else if (signal.toUpperCase() == off_payload.toUpperCase()) {
                if (reset) {
                    // Start timers
                    setOnTimer();
                    node.status({fill:"green",shape:"ring",text:off_payload+" received,send.Timed:"+on_time+"s"});
                    node.send(msg);
                    reset = false;
                } else {
                    // Nothing
                }
			}
        });
        
        this.on('close', offTimers);
        
        function setOnTimer() {
            timer1 = setTimeout(
                function() {
                    setOffTimer();
                    node.status({fill:"yellow",shape:"dot",text:"timed+"+on_payload+",send.Timed:"+node.on_duration+"s"});
                    var msg1 = { topic : lastOnMsg.topic, payload : on_payload };
                    node.send(msg1);
                }, 
                on_time * 1000);
        };

        function setOffTimer() {
            timer2 = setTimeout(
                function() {
                    setOnTimer();
                    node.status({fill:"yellow",shape:"ring",text:"timed+"+off_payload+",send.Timed:"+on_time+"s"});
                    var msg1 = { topic : lastOnMsg.topic, payload : off_payload };
                    node.send(msg1);
                }, 
                on_duration * 1000);
        };

        function offTimers() {
            clearTimeout(timer1);
            clearTimeout(timer2);
        }
    }

    RED.nodes.registerType("trigger-atleast-every-x", trgAtLeastNode);
};
